17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const PROCESSING_FEE = 5;
27	
28	const COMPONENT_TYPES = ["rune", "moonstone"];
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	
32	const LOYALTY_YEARS_THRESHOLD = 2;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	
37	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
38	
39	const DEDUCTIBLE_PER_DAMAGE = 100;
40	
41	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
42	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
43	
44	function countByType(items: Item[]): Record<string, number> {
45	  const counts: Record<string, number> = {};
46	  for (const item of items) {
47	    counts[item.type] = (counts[item.type] ?? 0) + 1;
48	  }
49	  return counts;
50	}
51	
52	function basePremiumForType(type: string): number {
53	  return BASE_PREMIUM[type] ?? 0;
54	}
55	
56	function cursedSurchargeFor(item: Item): number {
57	  return item.cursed ? basePremiumForType(item.type) * 0.5 : 0;
58	}
59	
60	function highEnchantmentSurchargeFor(item: Item): number {
61	  return (item.enchantment ?? 0) >= 5 ? basePremiumForType(item.type) * 0.3 : 0;
62	}
63	
64	function itemSurchargesFor(item: Item): number {
65	  return cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item);
66	}
67	
68	function loyaltyDiscountFor(basePremium: number, customer: CustomerContext): number {
69	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
70	    ? basePremium * LOYALTY_DISCOUNT_RATE
71	    : 0;
72	}
73	
74	function firstInsuranceSurchargeFor(basePremium: number): number {
75	  return basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
76	}
77	
78	function followUpDiscountFor(basePremium: number, customer: CustomerContext): number {
79	  return customer.previousQuotes >= 1
80	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
81	    : 0;
82	}
83	
84	function premiumForGroup(type: string, count: number): number {
85	  if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
86	    return BLOCK_PREMIUM;
87	  }
88	  return count * basePremiumForType(type);
89	}
