91	export function quote(items: Item[], customer: CustomerContext): number {
92	  const counts = countByType(items);
93	
94	  const basePremium = Object.entries(counts)
95	    .reduce((sum, [type, count]) => sum + premiumForGroup(type, count), 0);
96	
97	  const itemSurcharges = items.reduce((sum, item) =>
98	    sum + itemSurchargesFor(item), 0);
99	
100	  const policyAdjustment =
101	    - loyaltyDiscountFor(basePremium, customer)
102	    + firstInsuranceSurchargeFor(basePremium)
103	    - followUpDiscountFor(basePremium, customer);
104	
105	  return Math.ceil(basePremium + itemSurcharges + policyAdjustment + PROCESSING_FEE);
106	}
107	
108	function reimbursementFor(damage: Damage, policyItem: Item | undefined): number {
109	  return (policyItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
110	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
111	    : damage.amount;
112	}
113	
114	export function claim(policy: Item[], damages: Damage[]): { payout: number; remainingCap: number } {
115	  const payout = damages.reduce((sum, damage) => {
116	    const policyItem = policy.find(item => item.type === damage.type);
117	    return sum + (reimbursementFor(damage, policyItem) - DEDUCTIBLE_PER_DAMAGE);
118	  }, 0);
119	  return { payout: Math.floor(payout), remainingCap: 0 };
120	}
